// // Asynchronous 4-bit down counter that decrements on the falling edge of the input clock signal (div_clk) when the 'contando' signal is high. The counter resets to zero when the 'rst' signal is asserted. It compares its value to the specified 'time_value'; when the counter reaches this value, it resets to zero and asserts the 'terminado' output signal to indicate completion. If 'contando' is low, the 'terminado' output remains deasserted, regardless of the counter's value.
module top_module(div_clk,rst,time_value,contando, terminado);input div_clk; 
  input rst; 
  input contando; 
  input [3:0] time_value; 
  output reg terminado; 
  reg [3:0] contador; 
  always @(posedge div_clk or posedge rst) 
  begin 
  if(rst) 
  begin 
  contador <= 0; 
  terminado <= 0; 
  end 
  else 
  if(contando) 
  begin 
  if(contador == time_value) 
  begin 
  contador <= 0; 
  terminado <= 1; 
  end 
  else 
  begin 
  terminado <= 0; 
  contador <= contador + 1; 
  end 
  end 
  else 
  terminado <= 0; 
  end 
 endmodule
